/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Accepts a webhook URL, formats the notification payload as JSON, and
 * POSTs it to the configured endpoint. Stores delivered payloads in
 * memory for inspection (swap with a real HTTP client for production).
 *
 * Implements the NotificationAdapter interface as required by the
 * notification system architecture.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult, NotificationChannel } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface WebhookConfig {
  url: string;
  secret?: string;
}

/**
 * A delivered webhook request ready for inspection.
 */
export interface DeliveredWebhook {
  url: string;
  payload: WebhookBody;
  headers: Record<string, string>;
  timestamp: Date;
}

/**
 * The JSON body POSTed to the webhook endpoint.
 */
export interface WebhookBody {
  notificationId: string;
  type: string;
  channel: string;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
  createdAt: string;
}

// Simple URL validation: must start with http:// or https://
const URL_REGEX = /^https?:\/\/\S+$/;

export class WebhookAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'webhook';
  private logger = new Logger('WebhookAdapter');
  private deliveredWebhooks: DeliveredWebhook[] = [];
  private config: WebhookConfig;

  constructor(config: WebhookConfig) {
    this.config = config;
  }

  /**
   * Validate that a recipient string is a well-formed URL.
   */
  validateRecipient(recipient: string): string | null {
    if (!recipient || !URL_REGEX.test(recipient)) {
      return `Invalid webhook URL: ${recipient}`;
    }
    return null;
  }

  /**
   * Format the notification payload into the JSON body for the webhook.
   */
  formatPayload(payload: NotificationPayload): WebhookBody {
    return {
      notificationId: payload.id,
      type: payload.type,
      channel: payload.channel,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      metadata: payload.metadata,
      createdAt: payload.createdAt.toISOString(),
    };
  }

  /**
   * Build the HTTP headers for the webhook request.
   */
  private buildHeaders(): Record<string, string> {
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
    };
    if (this.config.secret) {
      headers['X-Webhook-Secret'] = this.config.secret;
    }
    return headers;
  }

  /**
   * Send a notification through the webhook channel.
   * Validates the recipient URL, formats the payload, and delivers via POST.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const targetUrl = payload.recipient || this.config.url;

    this.logger.info(`Preparing webhook to ${targetUrl}: ${payload.subject}`);

    // Validate recipient URL
    const validationError = this.validateRecipient(targetUrl);
    if (validationError) {
      this.logger.warn(`Validation failed for ${payload.id}: ${validationError}`);
      return {
        success: false,
        notificationId: payload.id,
        channel: this.channel,
        error: validationError,
      };
    }

    // Format payload
    const webhookBody = this.formatPayload(payload);
    const headers = this.buildHeaders();

    // Deliver (in-memory store; replace with HTTP POST in production)
    this.deliveredWebhooks.push({
      url: targetUrl,
      payload: webhookBody,
      headers,
      timestamp: new Date(),
    });

    this.logger.info(
      `Webhook delivered: ${payload.id} to ${targetUrl}`,
    );

    return {
      success: true,
      notificationId: payload.id,
      channel: this.channel,
    };
  }

  /**
   * Get all webhooks delivered through this adapter (for testing).
   */
  getDeliveredWebhooks(): DeliveredWebhook[] {
    return [...this.deliveredWebhooks];
  }

  /**
   * Clear delivered webhook history (for testing).
   */
  clearDeliveredWebhooks(): void {
    this.deliveredWebhooks = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    channel: 'webhook',
    recipient: 'https://hooks.example.com/notify',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    createdAt: new Date('2026-01-15T12:00:00Z'),
    ...overrides,
  };
}

describe('WebhookAdapter', () => {
  let adapter: WebhookAdapter;

  beforeEach(() => {
    adapter = new WebhookAdapter({ url: 'https://default.example.com/webhook' });
  });

  describe('channel', () => {
    it('should identify as webhook channel', () => {
      expect(adapter.channel).toBe('webhook');
    });
  });

  describe('validateRecipient', () => {
    it('should accept valid https URLs', () => {
      expect(adapter.validateRecipient('https://hooks.example.com/notify')).toBeNull();
      expect(adapter.validateRecipient('https://api.acme.co/webhooks/123')).toBeNull();
    });

    it('should accept valid http URLs', () => {
      expect(adapter.validateRecipient('http://localhost:3000/hook')).toBeNull();
    });

    it('should reject empty string', () => {
      expect(adapter.validateRecipient('')).toContain('Invalid webhook URL');
    });

    it('should reject URL without protocol', () => {
      expect(adapter.validateRecipient('hooks.example.com/notify')).toContain('Invalid webhook URL');
    });

    it('should reject URL with spaces', () => {
      expect(adapter.validateRecipient('https://hooks.example.com /notify')).toContain('Invalid webhook URL');
    });

    it('should reject non-http protocols', () => {
      expect(adapter.validateRecipient('ftp://files.example.com/hook')).toContain('Invalid webhook URL');
    });
  });

  describe('formatPayload', () => {
    it('should format notification payload as webhook body', () => {
      const payload = makePayload();
      const body = adapter.formatPayload(payload);

      expect(body.notificationId).toBe('notif-0001');
      expect(body.type).toBe('order_confirmation');
      expect(body.channel).toBe('webhook');
      expect(body.recipient).toBe('https://hooks.example.com/notify');
      expect(body.subject).toBe('Order Confirmation: order-1');
      expect(body.body).toContain('Widget x2');
      expect(body.createdAt).toBe('2026-01-15T12:00:00.000Z');
    });

    it('should include metadata when present', () => {
      const payload = makePayload({ metadata: { orderId: 'order-1', priority: 'high' } });
      const body = adapter.formatPayload(payload);

      expect(body.metadata).toEqual({ orderId: 'order-1', priority: 'high' });
    });

    it('should omit metadata when not present', () => {
      const payload = makePayload();
      const body = adapter.formatPayload(payload);

      expect(body.metadata).toBeUndefined();
    });
  });

  describe('send', () => {
    it('should send successfully for valid recipient URL', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('webhook');
      expect(result.error).toBeUndefined();
    });

    it('should store delivered webhook on success', async () => {
      await adapter.send(makePayload());

      const delivered = adapter.getDeliveredWebhooks();
      expect(delivered).toHaveLength(1);
      expect(delivered[0]?.url).toBe('https://hooks.example.com/notify');
      expect(delivered[0]?.payload.notificationId).toBe('notif-0001');
      expect(delivered[0]?.headers['Content-Type']).toBe('application/json');
    });

    it('should fail for invalid URL', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-a-url' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
    });

    it('should not store webhook on validation failure', async () => {
      await adapter.send(makePayload({ recipient: 'bad' }));
      expect(adapter.getDeliveredWebhooks()).toHaveLength(0);
    });

    it('should handle multiple sends', async () => {
      await adapter.send(makePayload({ id: 'n-1', recipient: 'https://a.com/hook' }));
      await adapter.send(makePayload({ id: 'n-2', recipient: 'https://b.com/hook' }));

      expect(adapter.getDeliveredWebhooks()).toHaveLength(2);
    });

    it('should include secret header when configured', async () => {
      const secretAdapter = new WebhookAdapter({
        url: 'https://default.example.com/webhook',
        secret: 'my-secret-token',
      });

      await secretAdapter.send(makePayload());

      const delivered = secretAdapter.getDeliveredWebhooks();
      expect(delivered[0]?.headers['X-Webhook-Secret']).toBe('my-secret-token');
    });

    it('should not include secret header when not configured', async () => {
      await adapter.send(makePayload());

      const delivered = adapter.getDeliveredWebhooks();
      expect(delivered[0]?.headers['X-Webhook-Secret']).toBeUndefined();
    });
  });

  describe('getDeliveredWebhooks / clearDeliveredWebhooks', () => {
    it('should return a copy of delivered webhooks', async () => {
      await adapter.send(makePayload());
      const first = adapter.getDeliveredWebhooks();
      const second = adapter.getDeliveredWebhooks();
      expect(first).not.toBe(second);
      expect(first).toEqual(second);
    });

    it('should clear all delivered webhooks', async () => {
      await adapter.send(makePayload());
      adapter.clearDeliveredWebhooks();
      expect(adapter.getDeliveredWebhooks()).toHaveLength(0);
    });
  });
});
